trigger AccountTrigger on Account (before insert, before update) {
    for (Account a : Trigger.new) {
        a.Description = 'Touched by trigger';
    }
}

trigger LeadTrigger on Lead (before update) {
    for (Lead l : Trigger.new) {
        Lead old = Trigger.oldMap.get(l.Id);
        if (l.Status != old.Status) {
            System.debug('Status changed for ' + l.Id);
        }
    }
}

trigger ContactTrigger on Contact (after insert) {
    Set<Id> acctIds = new Set<Id>();
    for (Contact c : Trigger.new) {
        if (c.AccountId != null) { acctIds.add(c.AccountId); }
    }
    List<Account> toUpdate = [SELECT Id FROM Account WHERE Id IN :acctIds];
    update toUpdate;
}

trigger AccountTrigger on Account (after insert, after update) {
    if (Trigger.isInsert) { AccountTriggerHandler.afterInsert(Trigger.new); }
    if (Trigger.isUpdate) { AccountTriggerHandler.afterUpdate(Trigger.new, Trigger.oldMap); }
}
